import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums, long k) {
        Arrays.sort(nums);
        int n = nums.length;
        int maxLen = 1;
        for (int i = 0; i < n; i++) {
            long target = nums[i] * k;
            int low = i;
            int high = n - 1;
            int best = i - 1;
            while (low <= high) {
                int mid = (low + high) / 2;
                if (nums[mid] <= target) {
                    best = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            int currentLen = best - i + 1;
            if (currentLen > maxLen) {
                maxLen = currentLen;
            }
        }
        return (long) n - (long) maxLen;
    }
}
